          "secondaryOutcomes": [
            {
              "measure": "Self-management behaviors",
              "description": "The Symptom Management Checklist will measure self-management behaviors and preventive behaviors for CINV. Participants will be sent a text link every day for 6 days after chemotherapy or complete this data on a form at home. This starts right after Time 1.",
              "timeFrame": "From baseline through the end of the study at 12 or 24 weeks"
            },
            {
              "measure": "Symptom severity",
              "description": "The Symptom Representation Questionnaire Part 1 is a 24 item self-report measure that will be used to identify the presence and severity of common treatment-related side effects (0 to 10 scale). Higher numbers indicate more severe symptoms. This measure asks participants to think about their symptoms over the last week",
